const rows = [];
for (const item of $input.all()) {
  const it = item.json;
  for (const [rid, b] of Object.entries(it.books)) {
    rows.push({ json: { type_id: it.type_id, region_id: Number(rid),
      best_sell: b.best_sell, best_buy: b.best_buy,
      sell_volume: b.sell_units, buy_volume: b.buy_units } });
  }
}
return rows;

const SALES_TAX = 0.045;
const BROKER_FEE = 0.03;
const MAX_BUDGET = 200000000; // потолок капитала на одну позицию, ISK — поправьте под себя

const results = [];
for (const item of $input.all()) {
  const it = item.json;
  const rids = Object.keys(it.books);

  for (const src of rids) for (const dst of rids) {
    if (src === dst) continue;
    const S = it.books[src], D = it.books[dst];
    if (S.sell_vwap == null || S.sell_units === 0) continue;
    const budgetUnits = Math.floor(MAX_BUDGET / S.sell_vwap);

    // Стратегия 1: мгновенный флип — сливаем в buy-ордера назначения (без брокерки)
    if (D.buy_vwap != null && D.buy_units > 0) {
      const units = Math.min(S.sell_units, D.buy_units, budgetUnits);
      const net = D.buy_vwap * (1 - SALES_TAX) - S.sell_vwap;
      const profit = units * net;
      if (units > 0 && profit > 0) {
        results.push({ json: {
          item_name: (it.name || String(it.type_id)).replace(/,/g, ' '),
          type_id: it.type_id,
          route: `${S.region_name} -> ${D.region_name} (мгновенно)`,
          buy_price: Math.round(S.sell_vwap * 100) / 100,
          buy_location: S.best_sell_location,
          sell_price: Math.round(D.buy_vwap * 100) / 100,
          sell_location: D.hub_station,
          units_available: units,
          net_margin_pct: net / S.sell_vwap * 100,
          net_profit_per_unit: net,
          total_potential_profit: profit,
          capital_required: Math.round(units * S.sell_vwap)
        }});
      }
    }

    // Стратегия 2: свой sell-ордер (медленнее, но дороже) — объём ограничен дневным оборотом назначения
    if (D.sell_marginal != null) {
      const hasHistory = dst in (it.daily_vol || {});
      const dstDaily = Number((it.daily_vol || {})[dst]) || 0;
      const orderCap = hasHistory ? Math.max(1, Math.round(dstDaily * 0.05)) : 10;
      const units = Math.min(S.sell_units, orderCap, budgetUnits);
      const net = D.sell_marginal * (1 - SALES_TAX - BROKER_FEE) - S.sell_vwap;
      const profit = units * net;
      if (units > 0 && profit > 0) {
        results.push({ json: {
          item_name: (it.name || String(it.type_id)).replace(/,/g, ' '),
          type_id: it.type_id,
          route: `${S.region_name} -> ${D.region_name} (ордером)`,
          buy_price: Math.round(S.sell_vwap * 100) / 100,
          buy_location: S.best_sell_location,
          sell_price: Math.round(D.sell_marginal * 100) / 100,
          sell_location: D.hub_station,
          units_available: units,
          net_margin_pct: net / S.sell_vwap * 100,
          net_profit_per_unit: net,
          total_potential_profit: profit,
          capital_required: Math.round(units * S.sell_vwap)
        }});
      }
    }
  }
}
results.sort((a, b) => b.json.total_potential_profit - a.json.total_potential_profit);
return results;

const items = $input.all();
const cache = {};

const getStationName = async (stationId) => {
  if (cache[stationId]) return cache[stationId];
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://esi.evetech.net/latest/universe/stations/${stationId}/`,
      qs: { datasource: 'tranquility' },
      json: true
    });
    cache[stationId] = res.name;
    return res.name;
  } catch (e) {
    return `Station ${stationId}`;
  }
};

const results = [];
for (const item of items) {
  const j = item.json;
  results.push({ json: { ...j,
    buy_station_name: await getStationName(j.buy_location),
    sell_station_name: await getStationName(j.sell_location)
  }});
}
return results;

const riskItems = $input.all();               // items с полем text (вердикт AI)
const opps = $('Resolve Station Names').all(); // те же items, в том же порядке, с данными по сделке

const combined = riskItems.map((r, i) => ({
  ...opps[i].json,
  risk: r.json.text ?? r.json.output ?? '',
  capital_required: Number(opps[i].json.buy_price) * Number(opps[i].json.units)
}));

combined.sort((a, b) => Number(b.total_profit) - Number(a.total_profit));

const totalCapital = combined.reduce((sum, c) => sum + c.capital_required, 0);
const totalProfit = combined.reduce((sum, c) => sum + Number(c.total_profit), 0);

const top = combined.slice(0, 5);
const lines = top.map((c, i) =>
  `${i + 1}. ${c.item_name} — ${c.route}\n` +
  `   ${Math.round(Number(c.buy_price))} → ${Math.round(Number(c.sell_price))} ISK, ${c.units} шт, прибыль ${Math.round(Number(c.total_profit))} ISK (${Number(c.net_margin_pct).toFixed(1)}%)\n` +
  `   🤖 ${c.risk}`
).join('\n\n');

const message = `📊 Найдено возможностей: ${combined.length}
Суммарная потенциальная прибыль: ${Math.round(totalProfit)} ISK
Требуется капитала: ${Math.round(totalCapital)} ISK

Топ-5 по прибыли:

${lines}`;

return [{ json: { message } }];

const REGIONS = {
  10000002: { name: 'Jita',    hub: 60003760 },
  10000043: { name: 'Amarr',   hub: 60008494 },
  10000032: { name: 'Dodixie', hub: 60011866 },
  10000030: { name: 'Rens',    hub: 60004588 },
  10000042: { name: 'Hek',     hub: 60005686 }
};

const items = $input.all().map(i => i.json);
const tasks = [];
for (const it of items)
  for (const rid of Object.keys(REGIONS)) tasks.push({ it, rid: Number(rid) });

const fetchOrders = async (t) => {
  try {
    const orders = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://esi.evetech.net/latest/markets/${t.rid}/orders/`,
      qs: { datasource: 'tranquility', order_type: 'all', type_id: t.it.type_id },
      json: true
    });
    return { ...t, orders };
  } catch (e) { return { ...t, orders: [] }; }
};

// параллельно пачками по 10, чтобы не душить ESI
const fetched = [];
for (let i = 0; i < tasks.length; i += 10) {
  fetched.push(...await Promise.all(tasks.slice(i, i + 10).map(fetchOrders)));
}

function walkSellBook(orders, target) {
  const sorted = orders.filter(o => !o.is_buy_order).sort((a, b) => a.price - b.price);
  let acc = 0, cost = 0, marginal = null;
  for (const o of sorted) {
    const take = Math.min(o.volume_remain, target - acc);
    acc += take; cost += take * o.price; marginal = o.price;
    if (acc >= target) break;
  }
  return acc ? { vwap: cost / acc, marginal, units: acc } : null;
}

// buy-ордера: только на самой хаб-станции или с range=region (иначе до них не доехать без крюка)
function walkBuyBook(orders, target, hubStation) {
  const sorted = orders
    .filter(o => o.is_buy_order && (o.location_id === hubStation || o.range === 'region'))
    .sort((a, b) => b.price - a.price);
  let acc = 0, revenue = 0, marginal = null;
  for (const o of sorted) {
    const take = Math.min(o.volume_remain, target - acc);
    acc += take; revenue += take * o.price; marginal = o.price;
    if (acc >= target) break;
  }
  return acc ? { vwap: revenue / acc, marginal, units: acc } : null;
}

const byType = {};
for (const r of fetched) {
  const t = r.it.type_id;
  if (!byType[t]) {
    const vols = Object.values(r.it.daily_vol || {}).map(Number).filter(v => v > 0);
    const hasAnyHistory = vols.length > 0;
    // пол 10 — только если истории нет вообще ни по одному региону; иначе честные 5% от максимального оборота, минимум 1
    const walkTarget = hasAnyHistory ? Math.max(1, Math.round(Math.max(...vols) * 0.05)) : 10;
    byType[t] = { type_id: t, name: r.it.name, daily_vol: r.it.daily_vol || {}, walk_target: walkTarget, books: {} };
  }
  const target = byType[t].walk_target;
  const sells = r.orders.filter(o => !o.is_buy_order);
  const sellDepth = walkSellBook(r.orders, target);
  const buyDepth  = walkBuyBook(r.orders, target, REGIONS[r.rid].hub);
  const bestSell = sells.length ? Math.min(...sells.map(o => o.price)) : null;
  const bestSellOrder = sells.find(o => o.price === bestSell);
  const buys = r.orders.filter(o => o.is_buy_order);
  byType[t].books[r.rid] = {
    region_name: REGIONS[r.rid].name,
    hub_station: REGIONS[r.rid].hub,
    sell_vwap: sellDepth?.vwap ?? null,
    sell_marginal: sellDepth?.marginal ?? null,
    sell_units: sellDepth?.units ?? 0,
    buy_vwap: buyDepth?.vwap ?? null,
    buy_units: buyDepth?.units ?? 0,
    best_sell: bestSell,
    best_sell_location: bestSellOrder?.location_id ?? null,
    best_buy: buys.length ? Math.max(...buys.map(o => o.price)) : null
  };
}
return Object.values(byType).map(v => ({ json: v }));
